import { writable } from 'svelte/store';

const DEFAULT_FEEDBACK = {
	summary: 'Choose a cell or use Assist for a hint.',
	type: 'info',
	hint: null,
	auto: null,
	error: null,
};

function createFeedback() {
	const store = writable(DEFAULT_FEEDBACK);

	return {
		subscribe: store.subscribe,

		set(feedback) {
			store.set({
				...DEFAULT_FEEDBACK,
				...feedback,
			});
		},

		info(summary, details = {}) {
			this.set({ ...details, summary, type: 'info' });
		},

		success(summary, details = {}) {
			this.set({ ...details, summary, type: 'success' });
		},

		warn(summary, details = {}) {
			this.set({ ...details, summary, type: 'warn' });
		},

		error(summary, details = {}) {
			this.set({ ...details, summary, type: 'error', error: summary });
		},

		clear() {
			store.set(DEFAULT_FEEDBACK);
		},
	};
}

export const feedback = createFeedback();
